<table class="compact-item-table">
  <thead>
    <tr>
      <th style="width: 5%;">#</th>
      <th style="width: 30%;">Description of Goods<br>Product Code<br>HSN/SAC</th>
      <th style="width: 12%;">Batch No. <br>Mfg - Exp</th>
      <th style="width: 8%;">Qty <br>UOM</th>
      <th style="width: 6%;">MRP</th>
      <th style="width: 6%;">Rate</th>
      <th style="width: 10%;">Taxable Value</th>
      <th style="width: 8%;">CGST %<br>Amt</th>
      <th style="width: 8%;">SGST %<br>Amt</th>
      <th style="width: 8%;">IGST %<br>Amt</th>
      <th style="width: 10%;">Amt Incl. Tax</th>
    </tr>
  </thead>
  <tbody>
    {% for item in doc.items %}
    {% set mfg_date = frappe.db.get_value("Batch", item.batch_no, "manufacturing_date") if item.batch_no else None %}
    {% set exp_date = frappe.db.get_value("Batch", item.batch_no, "expiry_date") if item.batch_no else None %}
    {% set total_amount = (item.base_amount or 0) + (item.igst_amount or 0) + (item.cgst_amount or 0) + (item.sgst_amount or
    0) %}
    <tr>
      <td>{{ loop.index }}.</td>
      <td>
        <span class="item-title">{{ item.item_name }}</span><br>
        {{ item.item_code }}<br>
        {{ item.gst_hsn_code or "" }}
